# Category: mfa_bypass

import os
import pyotp
from flask import Flask, request, redirect, url_for, session, flash, jsonify, render_template_string
from werkzeug.security import generate_password_hash, check_password_hash
from functools import wraps

app = Flask(__name__)
app.secret_key = os.urandom(24) # A strong secret key is crucial for session security

# Dummy User Database (In-memory for simplicity)
# In a real application, this would be a database.
# Passwords are pre-hashed. MFA secret is base32 encoded.
users = {
    "webuser1": {
        "password_hash": generate_password_hash("password123"),
        "mfa_enabled": True,
        "mfa_secret": pyotp.random_base32(), # Generate a random secret for webuser1
    },
    "webuser2": {
        "password_hash": generate_password_hash("password123"),
        "mfa_enabled": False,
        "mfa_secret": None, # No MFA secret needed if disabled
    },
    "apiuser": { # This user is for the /api/direct-login endpoint
        "password_hash": generate_password_hash("apipass"),
        "mfa_enabled": True, # MFA is enabled, but /api/direct-login will skip it
        "mfa_secret": pyotp.random_base32(), # Still good to have one if they try web login
    },
}

def login_required(f):
    """
    Decorator to protect routes that require a full login (after MFA if applicable).
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            flash("Please log in to access this page.", "warning")
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

def mfa_awaiting_verification_required(f):
    """
    Decorator to protect the MFA verification route, ensuring user is in the correct state.
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id_awaiting_mfa' not in session:
            flash("Invalid state for MFA verification. Please log in again.", "warning")
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

