# --- Routes ---

@app.route('/')
@login_required
def home():
    user_id = session['user_id']
    return render_template_string(BASE_HTML + HOME_HTML, user_id=user_id, users=users)

@app.route('/login', methods=['GET', 'POST'])
def login():
    if 'user_id' in session:
        return redirect(url_for('home')) # Already fully logged in

    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        user_data = users.get(username)

        if user_data and check_password_hash(user_data['password_hash'], password):
            # Password is correct
            if user_data['mfa_enabled']:
                # User has MFA enabled, redirect to MFA verification
                session['user_id_awaiting_mfa'] = username # Store username temporarily
                flash("Please enter your One-Time Password (OTP).", "info")
                return redirect(url_for('verify_mfa'))
            else:
                # User does not have MFA enabled, grant immediate access
                session['user_id'] = username
                flash("Login successful!", "success")
                return redirect(url_for('home'))
        else:
            flash("Invalid username or password.", "danger")
            return render_template_string(BASE_HTML + LOGIN_HTML, username=username) # Keep username in form

    return render_template_string(BASE_HTML + LOGIN_HTML)

@app.route('/verify_mfa', methods=['GET', 'POST'])
@mfa_awaiting_verification_required
def verify_mfa():
    user_id = session['user_id_awaiting_mfa']
    user_data = users.get(user_id)

    if not user_data or not user_data['mfa_enabled']:
        # This state should ideally not happen if mfa_awaiting_verification_required is strict
        # but as a safeguard.
        flash("MFA not enabled or user not found. Please log in again.", "danger")
        session.pop('user_id_awaiting_mfa', None)
        return redirect(url_for('login'))

    if request.method == 'POST':
        otp = request.form['otp']
        totp = pyotp.TOTP(user_data['mfa_secret'])

        if totp.verify(otp):
            session.pop('user_id_awaiting_mfa') # Clear temporary state
            session['user_id'] = user_id # Grant full login
            flash("MFA verification successful! You are now logged in.", "success")
            return redirect(url_for('home'))
        else:
            flash("Invalid One-Time Password (OTP). Please try again.", "danger")
            return render_template_string(BASE_HTML + VERIFY_MFA_HTML)

    return render_template_string(BASE_HTML + VERIFY_MFA_HTML)

@app.route('/logout')
def logout():
    session.pop('user_id', None)
    session.pop('user_id_awaiting_mfa', None) # Clean up any pending MFA state
    flash("You have been logged out.", "info")
    return redirect(url_for('login'))

# --- API Endpoint for Direct Login (Skips MFA) ---

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    data = request.get_json()
    if not data:
        return jsonify({"message": "Invalid JSON payload"}), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({"message": "Username and password are required"}), 400

    user_data = users.get(username)

    if user_data and check_password_hash(user_data['password_hash'], password):
        # Authentication successful
        # IMPORTANT: This endpoint *intentionally skips* MFA checks.
        # In a real API, you might issue an API token/JWT here.
        # For this example, we just return a success message.
        return jsonify({
            "message": "Direct login successful for API client.",
            "user_id": username,
            "api_access_granted": True # Indicate successful API access
        }), 200
    else:
        # Authentication failed
        return jsonify({"message": "Invalid username or password"}), 401

